<div class="page-head"><div><h1>Медиатека</h1><p>Изображения, документы, музыка и видео для публикаций и портфолио.</p></div></div>
<section class="panel" style="margin-bottom:18px"><h2>Загрузить файлы</h2><form method="post" enctype="multipart/form-data" action="<?=e(app_url('/studio/media/upload'))?>"><?=csrf_field()?><div class="field"><label>Файлы</label><input type="file" name="media[]" multiple accept="image/jpeg,image/png,image/webp,application/pdf,audio/mpeg,audio/ogg,video/mp4,video/webm,application/zip"><small>До 20 файлов за раз, каждый не больше 40 МБ.</small></div><button class="button primary">Загрузить в медиатеку</button></form></section>
<?php if($media):?><div class="media-grid"><?php foreach($media as $item):?><article class="media-card"><div class="media-card__preview"><?php if(str_starts_with((string)$item['mime_type'],'image/')):?><img src="<?=e(app_url('/media/'.(int)$item['id']))?>" alt="<?=e($item['alt_text']??'')?>" loading="lazy"><?php else:?><strong><?=e(strtoupper(pathinfo((string)$item['original_name'],PATHINFO_EXTENSION)?:'FILE'))?></strong><?php endif;?></div><div class="media-card__body"><b><?=e($item['title']??$item['original_name'])?></b><small><?=e($item['mime_type'])?> · <?=e(format_bytes((int)$item['file_size']))?></small><small><?=e($item['uploader_name'])?> · <?=e($item['created_at'])?></small><div class="table-actions" style="margin-top:9px"><a class="button small" target="_blank" href="<?=e(app_url('/media/'.(int)$item['id']))?>">Открыть</a><form method="post" data-confirm="Удалить этот файл из медиатеки?" action="<?=e(app_url('/studio/media/'.(int)$item['id'].'/delete'))?>"><?=csrf_field()?><button class="button small danger">Удалить</button></form></div></div></article><?php endforeach;?></div><?php else:?><div class="empty-state">Медиатека пока пуста.</div><?php endif;?>
